"use client";

import React, { useState, useEffect, useRef } from "react";
import { Send, Search, User, School, MapPin, Mail, Clock, Plus, Monitor } from "lucide-react";
import Fuse from "fuse.js";
import { motion, AnimatePresence } from "framer-motion";
import MessageBubble from "./MessageBubble.jsx";
import { useDoctors } from "../app/layout.js";

const DoctorInfo = ({ doctor }) => (
  <div className="space-y-4 py-1">
    <div className="flex items-center gap-4">
      <div className="w-10 h-10 rounded-full bg-white dark:bg-slate-800 flex items-center justify-center text-[var(--primary)] shadow-sm border border-slate-100 dark:border-slate-700">
        <User size={20} />
      </div>
      <div>
        <h3 className="text-[15px] font-bold text-[var(--text-primary)] leading-tight">{doctor.name}</h3>
        <p className="text-[11px] font-bold uppercase tracking-wider text-[var(--text-secondary)]">{doctor.department}</p>
      </div>
    </div>
    
    <div className="space-y-2.5 ml-1">
      <div className="flex items-center gap-2.5 text-[14px] text-[var(--text-primary)]">
        <School size={16} className="text-[var(--text-secondary)] opacity-70" />
        <span className="font-medium">{doctor.school}</span>
      </div>
      <div className="flex items-center gap-2.5 text-[14px] text-[var(--text-primary)]">
        <MapPin size={16} className="text-[var(--text-secondary)] opacity-70" />
        <span className="font-medium">Office: {doctor.office}</span>
      </div>
      <div className="flex items-center gap-2.5 text-[14px] text-[var(--primary)] font-bold group">
        <Mail size={16} className="opacity-80" />
        <a href={`mailto:${doctor.email}`} className="hover:underline underline-offset-4">
          {doctor.email}
          <span className="block text-[10px] font-normal text-[var(--text-secondary)] mt-0.5">(tap to email)</span>
        </a>
      </div>
    </div>

    <div className="mt-4 bg-white/40 dark:bg-black/20 rounded-2xl p-4 border border-slate-100 dark:border-slate-800">
      <div className="flex items-center gap-2 mb-3">
        <Clock size={14} className="text-[var(--text-secondary)]" />
        <span className="text-[11px] font-black uppercase tracking-widest text-[var(--text-secondary)]">Office Hours</span>
      </div>
      <div className="space-y-2 font-mono">
        {Object.entries(doctor.office_hours).map(([day, hours]) => (
          <div key={day} className="flex justify-between text-[12px]">
            <span className="font-bold text-[var(--text-primary)]">{day}</span>
            <span className="text-[var(--text-secondary)]">{hours}</span>
          </div>
        ))}
      </div>
    </div>
  </div>
);

export default function ChatWindow() {
  const { instructors, loading, theme, setTheme } = useDoctors();
  const [messages, setMessages] = useState([]);
  const [inputValue, setInputValue] = useState("");
  const [fuseInstance, setFuseInstance] = useState(null);
  const [suggestions, setSuggestions] = useState([]);
  const [isTyping, setIsTyping] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const chatEndRef = useRef(null);

  useEffect(() => {
    if (!loading && instructors.length > 0) {
      const fuseOptions = {
        threshold: 0.3,
        distance: 100,
        keys: [
          { name: "name", weight: 0.7 },
          { name: "department", weight: 0.2 },
          { name: "office", weight: 0.1 }
        ]
      };
      setFuseInstance(new Fuse(instructors, fuseOptions));
      setMessages([
        {
          id: "initial",
          sender: "system",
          content: "Hi! 👋 I can help you find HTU computing instructors. Try typing a name like 'Israa' or a department like 'Cyber Security'.",
          createdAt: new Date()
        }
      ]);
    }
  }, [loading, instructors]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isTyping]);

  const handleInputChange = (e) => {
    const value = e.target.value;
    setInputValue(value);

    if (fuseInstance && value.trim().length > 1) {
      const results = fuseInstance.search(value).slice(0, 5);
      setSuggestions(results);
      setSelectedIndex(-1);
    } else {
      setSuggestions([]);
    }
  };

  const handleSend = (selectedDoctor = null) => {
    const query = selectedDoctor ? selectedDoctor.name : inputValue.trim();
    if (!query) return;

    const userMsg = {
      id: `u-${Date.now()}`,
      sender: "user",
      content: query,
      createdAt: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputValue("");
    setSuggestions([]);
    setIsTyping(true);

    // designdox 6.1: search delay
    setTimeout(() => {
      setIsTyping(false);
      if (fuseInstance) {
        const results = selectedDoctor ? [{ item: selectedDoctor }] : fuseInstance.search(query);
        const systemMsg = {
          id: `s-${Date.now()}`,
          sender: "system",
          content: results.length > 0 
            ? <DoctorInfo doctor={results[0].item} /> 
            : `I couldn't find any instructors matching "${query}". Try checking the spelling or browse by department. 😔`,
          createdAt: new Date()
        };
        setMessages(prev => [...prev, systemMsg]);
      }
    }, 600);
  };

  const handleKeyDown = (e) => {
    if (suggestions.length > 0) {
      if (e.key === "ArrowDown") {
        e.preventDefault();
        setSelectedIndex(prev => (prev < suggestions.length - 1 ? prev + 1 : prev));
      } else if (e.key === "ArrowUp") {
        e.preventDefault();
        setSelectedIndex(prev => (prev > 0 ? prev - 1 : -1));
      } else if (e.key === "Enter" && selectedIndex >= 0) {
        e.preventDefault();
        handleSend(suggestions[selectedIndex].item);
      } else if (e.key === "Escape") {
        setSuggestions([]);
      }
    }
  };

  const handleQuickReply = (text) => {
    setInputValue(text);
    // Auto-focus input
    document.getElementById("chat-input")?.focus();
  };

  const toggleTheme = () => {
    setTheme(prev => prev === "light" ? "dark" : "light");
  };

  return (
    <div className="flex-1 flex flex-col relative h-full bg-[var(--bg-chat)]">
      {/* designdox 4.1 Header */}
      <header className="px-5 py-3.5 flex items-center justify-between premium-glass sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-[var(--primary)] to-blue-400 flex items-center justify-center text-white shadow-md">
            <Monitor size={20} strokeWidth={2.5} />
          </div>
          <div>
            <h2 className="text-[15px] font-bold text-[var(--text-primary)] leading-tight">MubxBot</h2>
            <p className="text-[12px] font-medium text-[var(--text-secondary)] mt-0.5 flex items-center gap-1.5">
              <span className="w-2 h-2 rounded-full bg-green-500" />
              HTU Computing Assistant
            </p>
          </div>
        </div>
        <button 
          onClick={toggleTheme}
          className="w-9 h-9 rounded-full flex items-center justify-center hover:bg-black/5 dark:hover:bg-white/5 transition-colors"
        >
          {theme === "light" ? "🌙" : "☀️"}
        </button>
      </header>

      {/* Chat Area */}
      <div className="flex-1 overflow-y-auto pt-6 pb-4 px-1 no-scrollbar scroll-smooth">
        <AnimatePresence initial={false}>
          {messages.map((msg) => (
            <MessageBubble key={msg.id} sender={msg.sender}>
              {msg.content}
            </MessageBubble>
          ))}
          {isTyping && (
            <MessageBubble key="typing" sender="system" isTyping={true} />
          )}
        </AnimatePresence>
        
        {/* designdox 4.3 Quick Replies */}
        {!isTyping && messages.length > 0 && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="flex flex-wrap gap-2 px-6 mt-2 mb-4"
          >
            {["Israa Saadeh", "Cyber Security", "Search Name", "Browse Department"].map((text) => (
              <button
                key={text}
                onClick={() => handleQuickReply(text)}
                className="px-4 py-2 rounded-full border-1.5 border-[var(--primary)] text-[var(--primary)] text-[14px] font-medium hover:bg-[var(--primary)]/10 active:scale-[0.97] transition-all"
              >
                {text}
              </button>
            ))}
          </motion.div>
        )}
        <div ref={chatEndRef} className="h-4" />
      </div>

      {/* designdox 4.4 Input Bar */}
      <div className="px-4 py-3 bg-[var(--bg-chat)] relative z-30">
        <AnimatePresence>
          {suggestions.length > 0 && (
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: 5 }}
              className="absolute bottom-full left-4 right-4 mb-3 bg-white/95 dark:bg-slate-900/95 rounded-2xl shadow-2xl border border-slate-100 dark:border-slate-800 overflow-hidden backdrop-blur-2xl"
            >
              <div className="p-1 space-y-1">
                {suggestions.map((res, idx) => (
                  <button
                    key={res.item.name}
                    className={`w-full flex items-center justify-between p-3 rounded-xl text-left transition-all ${
                      idx === selectedIndex 
                        ? "bg-[var(--primary)] text-white" 
                        : "hover:bg-slate-100 dark:hover:bg-slate-800/50 text-[var(--text-primary)]"
                    }`}
                    onClick={() => handleSend(res.item)}
                  >
                    <div className="flex items-center gap-3">
                      <Search size={14} className={idx === selectedIndex ? "text-white" : "text-[var(--text-secondary)]"} />
                      <div>
                        <div className="text-[14px] font-bold">{res.item.name}</div>
                        <div className={`text-[10px] uppercase font-bold tracking-widest ${idx === selectedIndex ? "text-white/70" : "text-[var(--text-secondary)]"}`}>{res.item.department}</div>
                      </div>
                    </div>
                  </button>
                ))}
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        <div className="flex items-center gap-3 max-w-2xl mx-auto">
          <button className="w-10 h-10 flex items-center justify-center text-[var(--text-secondary)] hover:bg-black/5 dark:hover:bg-white/5 rounded-full transition-colors">
            <Plus size={24} />
          </button>
          
          <div className="flex-1 flex items-center gap-2 bg-slate-200/50 dark:bg-slate-800/50 p-1 rounded-full group focus-within:ring-2 focus-within:ring-[var(--primary)]/30 transition-all">
            <input
              id="chat-input"
              type="text"
              value={inputValue}
              onChange={handleInputChange}
              onKeyDown={(e) => {
                if (e.key === "Enter" && selectedIndex === -1) handleSend();
                else handleKeyDown(e);
              }}
              placeholder="Type doctor name..."
              className="flex-1 bg-transparent px-4 py-2 outline-none placeholder:text-[var(--text-secondary)] text-[15px]"
            />
            <motion.button
              whileTap={{ scale: 0.9 }}
              onClick={() => handleSend()}
              disabled={!inputValue.trim()}
              className="bg-[var(--primary)] text-white p-2 rounded-full shadow-lg disabled:opacity-50 transition-all flex items-center justify-center"
            >
              <Send size={18} />
            </motion.button>
          </div>
        </div>
      </div>
    </div>
  );
}
